using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and their impact on civilization." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented design.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Ada Lovelace", InstructorBio = "Dr. Lovelace has 15 years of experience in software engineering education and specializes in introductory programming pedagogy.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (lists, trees, graphs) and algorithm design techniques (sorting, searching, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. Alan Turing", InstructorBio = "Dr. Turing is a renowned researcher in computational theory with over 50 publications in algorithm design.", IsFeatured = true },
        new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transaction processing, and an introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Edgar Codd", InstructorBio = "Dr. Codd has extensive industry experience in database architecture and currently researches distributed data systems.", IsFeatured = false },
        new() { Id = 4, DepartmentId = 2, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Isaac Newton", InstructorBio = "Dr. Newton is an award-winning mathematics educator with a passion for making calculus accessible to all students.", IsFeatured = true },
        new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emmy Noether", InstructorBio = "Dr. Noether specializes in abstract algebra and has mentored numerous graduate students in mathematical research.", IsFeatured = false },
        new() { Id = 6, DepartmentId = 3, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Marie Curie", InstructorBio = "Dr. Curie is a distinguished physicist with research focus on experimental methods in undergraduate education.", IsFeatured = true },
        new() { Id = 7, DepartmentId = 3, CourseCode = "PHYS 201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. James Maxwell", InstructorBio = "Dr. Maxwell's research in electromagnetic theory informs his engaging lecture style and modern lab curriculum.", IsFeatured = false },
        new() { Id = 8, DepartmentId = 4, CourseCode = "ENG 101", Title = "Composition and Rhetoric", Description = "Develop effective academic writing skills. Emphasis on argumentation, research, and revision.", Credits = 3, Schedule = "Mon/Wed 9:00–10:15 AM", InstructorName = "Dr. Virginia Woolf", InstructorBio = "Dr. Woolf is a published author and writing instructor dedicated to helping students find their voice.", IsFeatured = false },
        new() { Id = 9, DepartmentId = 4, CourseCode = "ENG 250", Title = "World Literature", Description = "Survey of major literary works from diverse cultures and time periods.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Chinua Achebe", InstructorBio = "Dr. Achebe brings a global perspective to literature studies with expertise in postcolonial narratives.", IsFeatured = true },
        new() { Id = 10, DepartmentId = 5, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations and events from antiquity through the medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Howard Zinn", InstructorBio = "Dr. Zinn emphasizes social history and primary source analysis in his teaching approach.", IsFeatured = false },
    ];

    private readonly List<EnrollmentRequest> _enrollments = [];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public Department? GetDepartmentForCourse(int courseId)
    {
        var course = GetCourse(courseId);
        return course is null ? null : GetDepartment(course.DepartmentId);
    }

    public void SubmitEnrollment(EnrollmentRequest request) => _enrollments.Add(request);
}

