@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                if (dept.Id == DepartmentId)
                {
                    <option value="@dept.Id" selected>@dept.Code — @dept.Name</option>
                }
                else
                {
                    <option value="@dept.Id">@dept.Code — @dept.Name</option>
                }
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                var dept = Catalog.GetDepartmentForCourse(course.Id);
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@dept?.Name</td>
                    <td>@course.Credits</td>
                    <td><a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="/courses">Back to course list</a>
}
else
{
    <PageTitle>@course.CourseCode — @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/courses?departmentId=@department?.Id">@department?.Name</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@course.Description</p>

            <h2>Instructor</h2>
            <h5>@course.InstructorName</h5>
            <p>@course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <dl>
                        <dt>Credits</dt>
                        <dd>@course.Credits</dd>
                        <dt>Schedule</dt>
                        <dd>@course.Schedule</dd>
                        <dt>Department</dt>
                        <dd>@department?.Name</dd>
                    </dl>
                    <a href="/enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? department;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
        if (course is not null)
            department = Catalog.GetDepartment(course.DepartmentId);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit an enrollment request.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Request submitted!</strong> Your enrollment request for
        <em>@Catalog.GetCourse(Model.CourseId)?.Title</em> has been received.
    </div>
    <a href="/courses">Browse more courses</a>
}
else
{
    <form method="post" class="col-md-6">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" />
            @if (errors.ContainsKey(nameof(Model.StudentName)))
            {
                <div class="text-danger">@errors[nameof(Model.StudentName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" />
            @if (errors.ContainsKey(nameof(Model.StudentId)))
            {
                <div class="text-danger">@errors[nameof(Model.StudentId)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select">
                <option value="0">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    if (course.Id == Model.CourseId)
                    {
                        <option value="@course.Id" selected>@course.CourseCode — @course.Title</option>
                    }
                    else
                    {
                        <option value="@course.Id">@course.CourseCode — @course.Title</option>
                    }
                }
            </select>
            @if (errors.ContainsKey(nameof(Model.CourseId)))
            {
                <div class="text-danger">@errors[nameof(Model.CourseId)]</div>
            }
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = [];
    private bool submitted;
    private Dictionary<string, string> errors = new();

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    protected override void OnParametersSet()
    {
        if (HttpContext?.Request.Method == "POST")
        {
            errors.Clear();
            var validationResults = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
            var context = new System.ComponentModel.DataAnnotations.ValidationContext(Model);
            if (!System.ComponentModel.DataAnnotations.Validator.TryValidateObject(Model, context, validationResults, true))
            {
                foreach (var result in validationResults)
                {
                    foreach (var member in result.MemberNames)
                    {
                        if (!errors.ContainsKey(member))
                            errors[member] = result.ErrorMessage ?? "Invalid";
                    }
                }
            }
            else
            {
                Catalog.SubmitEnrollment(Model);
                submitted = true;
            }
        }
    }
}

